const char* CSS_STYLES = R"(*{margin:0;padding:0;box-sizing:border-box}body{font-family:Arial,sans-serif;background:#667eea;min-height:100vh;color:#333}.container{max-width:900px;margin:0 auto;padding:20px}h1{text-align:center;color:#fff;margin-bottom:30px;font-size:2.5rem}h3{color:#333;margin:20px 0 15px}h4{color:#667eea;margin:10px 0 5px;font-size:0.95rem}.status-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:15px;margin-bottom:20px}.status-card{background:#fff;border-radius:15px;padding:20px;box-shadow:0 4px 15px rgba(0,0,0,0.1);margin-bottom:20px}.status-card-inner{background:#f8f9fa;border-radius:10px;padding:15px;text-align:center;border:1px solid #e9ecef}.sensor-group{margin-bottom:25px}.sensor-group-title{color:#333;margin:0 0 15px 0;font-size:1.2rem;font-weight:600;border-bottom:2px solid #667eea;padding-bottom:10px}.status-card h3{color:#666;margin-bottom:15px;font-size:1.1rem}.status-card h4{color:#667eea;margin-bottom:10px;font-size:1rem;display:flex;justify-content:space-between;align-items:center}.value{font-size:2.2rem;font-weight:bold;color:#667eea;margin:10px 0}.controls{background:#fff;border-radius:15px;padding:25px;margin-bottom:20px;box-shadow:0 4px 15px rgba(0,0,0,0.1);text-align:center}.controls h3{margin-bottom:20px;color:#333}.controls p{text-align:left;margin:10px 0;color:#555}.btn{padding:10px 20px;border:none;border-radius:8px;font-size:0.95rem;font-weight:600;cursor:pointer;margin:5px;text-decoration:none;display:inline-block;transition:all 0.2s}.btn-primary{background:#667eea;color:#fff}.btn-primary:hover{background:#5568d3}.btn-danger{background:#ff6b6b;color:#fff;padding:5px 10px;font-size:0.85rem}.btn-danger:hover{background:#ff5252}.btn-secondary{background:#6c757d;color:#fff}.btn-secondary:hover{background:#5a6268}.btn-success{background:#28a745;color:#fff}.btn-success:hover{background:#218838}.btn-info{background:#17a2b8;color:#fff}.btn-info:hover{background:#138496}.network-info{background:#fff;border-radius:15px;padding:25px;margin-bottom:20px;box-shadow:0 4px 15px rgba(0,0,0,0.1)}.network-info h3{margin-bottom:15px;color:#333}.network-info p{margin-bottom:10px;color:#666;text-align:left}.network-info a{color:#667eea;text-decoration:none;font-weight:600}.form-group{margin-bottom:15px}.form-group label{display:block;margin-bottom:5px;font-weight:500;color:#555;font-size:0.9rem}.form-control{width:100%;padding:10px;border:2px solid #e9ecef;border-radius:6px;font-size:0.95rem;background:#fff}.form-control:focus{outline:none;border-color:#667eea}.form-row{display:flex;gap:10px;margin-bottom:10px;flex-wrap:wrap}.form-col{flex:1;min-width:140px}.alert{padding:15px;border-radius:8px;margin-bottom:20px}.alert-success{background:#d4edda;color:#155724;border:1px solid #c3e6cb}.alert-danger{background:#f8d7da;color:#721c24;border:1px solid #f5c6cb}.alert-warning{background:#fff3cd;color:#856404;border:1px solid #ffeaa7}.success{color:#28a745;font-weight:bold}.error{color:#dc3545;font-weight:bold}.progress-bar{width:100%;height:20px;background:#e9ecef;border-radius:10px;overflow:hidden;margin-bottom:10px}.progress-fill{height:100%;background:#667eea;width:0%}.program-info{background:#fff;border-radius:15px;padding:25px;margin-bottom:20px;box-shadow:0 4px 15px rgba(0,0,0,0.1)}.program-info h3{color:#333;margin-bottom:15px}.stage-info{background:#f8f9fa;padding:15px;border-radius:8px;margin-bottom:15px}.stage-info h4{color:#667eea;margin-bottom:10px}.stage-params{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.param{text-align:center}.param-label{font-size:0.9rem;color:#666;margin-bottom:5px}.param-value{font-size:1.2rem;font-weight:bold;color:#333}.loading{text-align:center;padding:40px;color:#666}.checkbox-group{margin:10px 0}.checkbox-group label{display:block;margin:5px 0;font-weight:normal;font-size:0.9rem}@media (max-width:768px){.container{padding:10px}h1{font-size:2rem}.status-grid{grid-template-columns:1fr;gap:10px}.status-card{padding:15px}.status-card-inner{padding:10px}.value{font-size:1.8rem}.btn{width:100%;margin:5px 0}.form-row{flex-direction:column}.form-col{min-width:100%}})";

#endif // WEB_STYLES_MIN_H
